import { describe, expect, it } from 'vitest';

import { isAccept, isDefer, isReject, Verdict } from '@a0n/bitwise/triton-verdict';

import { natCostAlgebra } from './cost-algebra';
import {
  hotReplicaAdmission,
  replicaTotalHeat,
  THERMAL_HARD_LIMIT_FACTOR,
} from './cost-algebra-entropy';

// `natCostAlgebra` has `score = id`, so `replicaTotalHeat(A, s, k) === k * s`
// for `k >= 1`. That makes the heat exactly controllable for each band.

describe('hotReplicaAdmission — 3-way thermal verdict', () => {
  it('Accept: comfortably under the soft ceiling (admitted, isAccept)', () => {
    // heat = 2 * 3 = 6 <= ceiling 10.
    const d = hotReplicaAdmission(natCostAlgebra, 3, 2, 10);
    expect(d.totalHeat).toBe(6);
    expect(d.admitted).toBe(true);
    expect(d.verdict).toBe(Verdict.Accept);
    expect(isAccept(d.verdict)).toBe(true);
    // legacy collapse: admitted === isAccept(verdict)
    expect(d.admitted).toBe(isAccept(d.verdict));
    expect(d.deficit).toBe(0);
  });

  it('Decline: over the hard thermal limit (structurally unsafe, would melt)', () => {
    // heat = 2 * 30 = 60. ceiling 10, default hardLimit = 10 * 2 = 20. 60 > 20.
    const d = hotReplicaAdmission(natCostAlgebra, 30, 2, 10);
    expect(d.totalHeat).toBe(60);
    expect(d.hardLimit).toBe(10 * THERMAL_HARD_LIMIT_FACTOR);
    expect(d.admitted).toBe(false);
    expect(d.verdict).toBe(Verdict.Decline);
    expect(isReject(d.verdict)).toBe(true);
    // legacy collapse: Decline still maps to admitted === false.
    expect(d.admitted).toBe(isAccept(d.verdict));
    expect(d.deficit).toBe(50);
  });

  it('Abstain: the thermal middle — over soft ceiling, under hard limit (admit-with-throttle)', () => {
    // heat = 2 * 8 = 16. ceiling 10 (over it), default hardLimit 20 (under it).
    const d = hotReplicaAdmission(natCostAlgebra, 8, 2, 10);
    expect(d.totalHeat).toBe(16);
    expect(d.ceiling).toBe(10);
    expect(d.hardLimit).toBe(20);
    // The throttle band lives strictly between the two limits.
    expect(d.totalHeat).toBeGreaterThan(d.ceiling);
    expect(d.totalHeat).toBeLessThanOrEqual(d.hardLimit);
    expect(d.verdict).toBe(Verdict.Abstain);
    expect(isDefer(d.verdict)).toBe(true);
    // The bool cannot express the middle: Abstain collapses to admitted=false,
    // identical to the old binary behavior (heat > ceiling was rejected).
    expect(d.admitted).toBe(false);
    expect(d.admitted).toBe(isAccept(d.verdict));
    // but it is NOT a structural Decline — the verdict recovers what the bool lost.
    expect(isReject(d.verdict)).toBe(false);
    expect(d.deficit).toBe(6);
  });

  it('boundary: exactly at the soft ceiling is Accept; exactly at the hard limit is Abstain', () => {
    // heat = 1 * 10 = 10 === ceiling ⇒ Accept (<= ceiling).
    const atCeiling = hotReplicaAdmission(natCostAlgebra, 10, 1, 10);
    expect(atCeiling.totalHeat).toBe(10);
    expect(atCeiling.verdict).toBe(Verdict.Accept);

    // heat = 1 * 20 = 20 === hardLimit ⇒ Abstain (<= hardLimit, > ceiling).
    const atHardLimit = hotReplicaAdmission(natCostAlgebra, 20, 1, 10);
    expect(atHardLimit.totalHeat).toBe(20);
    expect(atHardLimit.verdict).toBe(Verdict.Abstain);
  });

  it('explicit hardLimit === ceiling removes the throttle band (faithful 2-way Accept/Decline)', () => {
    // heat = 1 * 16 = 16 > ceiling 10 with hardLimit pinned to ceiling ⇒ no
    // Abstain band, so it Declines rather than throttles.
    const d = hotReplicaAdmission(natCostAlgebra, 16, 1, 10, 10);
    expect(d.hardLimit).toBe(10);
    expect(d.verdict).toBe(Verdict.Decline);
    expect(isDefer(d.verdict)).toBe(false);
  });
});

describe('hotReplicaAdmission — preserved legacy behavior', () => {
  it('still computes totalHeat, deficit, sourceScore, replicas as before', () => {
    const d = hotReplicaAdmission(natCostAlgebra, 7, 3, 100);
    expect(d.totalHeat).toBe(replicaTotalHeat(natCostAlgebra, 7, 3));
    expect(d.totalHeat).toBe(21);
    expect(d.admitted).toBe(true);
    expect(d.deficit).toBe(0);
    expect(d.sourceScore).toBe(7);
    expect(d.replicas).toBe(3);
  });
});
